def myPow(x, n):
    if n == 0:
        return 1.0
    if n < 0:
        return 1.0 / myPow(x, -n)

    half = myPow(x, n // 2)
    if n % 2 == 0:
        return half * half
    else:
        return x * half * half

cppCode:
double myPow(double x, int n) {
    if (n == 0) return 1.0;
    if (n < 0) {
        // Handle INT_MIN overflow: -INT_MIN overflow. Cast to long long.
        long long N = n;
        return 1.0 / myPow(x, -N);
    }
    double half = myPow(x, n / 2);
    if (n % 2 == 0) {
        return half * half;
    } else {
        return x * half * half;
    }
}

