def decodeString(s):
    def decode(i):
        res = []
        num = 0
        while i < len(s):
            char = s[i]
            if char.isdigit():
                num = num * 10 + int(char)
            elif char == '[':
                # Recurse
                decoded, next_i = decode(i + 1)
                res.append(num * decoded)
                num = 0
                i = next_i
            elif char == ']':
                return ''.join(res), i
            else:
                res.append(char)
            i += 1
        return ''.join(res), i

    res, _ = decode(0)
    return res

