string decodeString(string s) {
    int idx = 0;
    auto decode = [&](auto& self) -> string {
        string res = "";
        int num = 0;
        while (idx < s.size()) {
            char c = s[idx];
            if (isdigit(c)) {
                num = num * 10 + (c - '0');
            } else if (c == '[') {
                idx++; // skip '['
                string decoded = self(self);
                while (num > 0) {
                    res += decoded;
                    num--;
                }
            } else if (c == ']') {
                return res;
            } else {
                res += c;
            }
            idx++;
        }
        return res;
    };
    return decode(decode);
}

