def makeSpecial(s):
    count = 0
    i = 0
    res = []
    for j, char in enumerate(s):
        count += 1 if char == '1' else -1
        if count == 0:
            # Split found. Recurse on inner portion s[i+1:j]
            res.append('1' + makeSpecial(s[i + 1:j]) + '0')
            i = j + 1

    # Sort sub-segments in descending order to maximize value
    res.sort(reverse=True)
    return ''.join(res)

cppCode:
string makeSpecial(string s) {
    int count = 0, i = 0;
    vector<string> res;
    for (int j = 0; j < s.size(); ++j) {
        count += (s[j] == '1') ? 1 : -1;
        if (count == 0) {
            res.push_back("1" + makeSpecial(s.substr(i + 1, j - i - 1)) + "0");
            i = j + 1;
        }
    }
    sort(res.begin(), res.end(), greater<string>());
    string ans = "";
    for (string& str : res) ans += str;
    return ans;
}

