def evaluate(expression):
    scope = [{}]

    def get_val(x):
        if x[0] in '-0123456789':
            return int(x)
        # Lookup in scopes stack from top to bottom
        for s in reversed(scope):
            if x in s:
                return s[x]
        return 0

    def parse(s):
        # Tokenize space-separated items, ignoring inner parentheses
        res = []
        buf = []
        bal = 0
        for char in s:
            if char == '(':
                bal += 1
            elif char == ')':
                bal -= 1
            if char == ' ' and bal == 0:
                res.append(''.join(buf))
                buf = []
            else:
                buf.append(char)
        if buf:
            res.append(''.join(buf))
        return res

    def evaluate_inner(expr):
        if expr[0] != '(':
            return get_val(expr)

        # Strip outer parentheses
        tokens = parse(expr[1:-1])
        cmd = tokens[0]

        if cmd == 'add':
            return evaluate_inner(tokens[1]) + evaluate_inner(tokens[2])
        elif cmd == 'mult':
            return evaluate_inner(tokens[1]) * evaluate_inner(tokens[2])
        else: # let
            scope.append(dict(scope[-1])) # Push new scope
            for i in range(1, len(tokens) - 1, 2):
                var = tokens[i]
                val_expr = tokens[i + 1]
                scope[-1][var] = evaluate_inner(val_expr)
            res = evaluate_inner(tokens[-1])
            scope.pop() # Pop scope
            return res

    return evaluate_inner(expression)

