int evaluate(string expression) {
    vector<unordered_map<string, int>> scope;
    scope.push_back({});

    auto get_val = [&](string x) -> int {
        if (isdigit(x[0]) || x[0] == '-') return stoi(x);
        for (auto it = scope.rbegin(); it != scope.rend(); ++it) {
            if (it->count(x)) return (*it)[x];
        }
        return 0;
    };

    auto parse = [](string s) -> vector<string> {
        vector<string> res;
        string buf = "";
        int bal = 0;
        for (char c : s) {
            if (c == '(') bal++;
            else if (c == ')') bal--;
            if (c == ' ' && bal == 0) {
                res.push_back(buf);
                buf = "";
            } else {
                buf += c;
            }
        }
        if (!buf.empty()) res.push_back(buf);
        return res;
    };

    auto evaluate_inner = [&](auto& self, string expr) -> int {
        if (expr[0] != '(') return get_val(expr);

        // strip brackets
        vector<string> tokens = parse(expr.substr(1, expr.size() - 2));
        string cmd = tokens[0];

        if (cmd == "add") {
            return self(self, tokens[1]) + self(self, tokens[2]);
        } else if (cmd == "mult") {
            return self(self, tokens[1]) * self(self, tokens[2]);
        } else { // let
            scope.push_back(scope.back()); // Push scope
            for (size_t i = 1; i < tokens.size() - 1; i += 2) {
                scope.back()[tokens[i]] = self(self, tokens[i+1]);
            }
            int res = self(self, tokens.back());
            scope.pop_back(); // Pop scope
            return res;
        }
    };

    return evaluate_inner(evaluate_inner, expression);
}

string countOfAtoms(string formula) {
    int n = formula.size();
    vector<map<string, int>> stack;
    stack.push_back({});
    int i = 0;

    while (i < n) {
        if (formula[i] == '(') {
            stack.push_back({});
            i++;
        } else if (formula[i] == ')') {
            i++;
            int start = i;
            while (i < n && isdigit(formula[i])) i++;
            string mult_str = formula.substr(start, i - start);
            int mult = mult_str.empty() ? 1 : stoi(mult_str);

            auto top = stack.back();
            stack.pop_back();
            for (auto& [elem, count] : top) {
                stack.back()[elem] += count * mult;
            }
        } else {
            // Element
            int start = i++;
            while (i < n && islower(formula[i])) i++;
            string elem = formula.substr(start, i - start);

            // Count
            start = i;
            while (i < n && isdigit(formula[i])) i++;
            string count_str = formula.substr(start, i - start);
            int count = count_str.empty() ? 1 : stoi(count_str);

            stack.back()[elem] += count;
        }
    }

    string ans = "";
    for (auto& [elem, count] : stack[0]) {
        ans += elem;
        if (count > 1) ans += to_string(count);
    }
    return ans;
}

